
(function() {
  const fallbackLang = 'en';
  const supportedLangs = ['en','el','fr','de','es','it','pt','ru','zh','ja','ko','ar','pl','hi','vi','nl','cs','da','th','et'];

  function detectLang() {
    const lang = navigator.language || navigator.userLanguage || fallbackLang;
    return lang.split('-')[0];
  }

  async function fetchLangMap(lang) {
    try {
      const res = await fetch(`https://weshare-ai-language.vercel.app/api/translate?lang=${lang}`);
      const json = await res.json();
      return json?.data || {};
    } catch (e) {
      console.warn('[WeShare AI] Language fetch failed:', e);
      return {};
    }
  }

  async function initLangLoader() {
    const lang = detectLang();
    window._weshareLangMap = await fetchLangMap(lang);
    window._weshareLangCode = lang;
    const evt = new Event('weshareLanguageReady');
    window.dispatchEvent(evt);
  }

  initLangLoader();
})();
